package main
import "fmt"
func main() {

    n := 0

    fmt.Scan(&n)

    animais := make([]int, n)

    solteiros := make(map[int]int)
    for i := range animais {
        fmt.Scan(&animais[i])
    }

    numPares := 0
    for _, animal := range  animais {
        if solteiros[-animal] > 0 {
            solteiros[-animal]--
            numPares++
        } else {
            solteiros[animal]++
        }
    }

    fmt.Println(numPares)
}
